THE CLAIM:
{
 "title": "Base counts basic PDUs the venture cannot sell, halving the market",
 "narrative": "The model assumes the venture can sell into the full €300M rack-PDU market. But Grand View, the source of that figure, says the non-intelligent segment held the largest revenue share in 2025, and the venture sells only intelligent PDUs. About half the €300M is basic units the product cannot address, so the Year-1 number is inflated about 2x.",
 "mechanism": [
  {
   "step": "trigger",
   "text": "Grand View says non-intelligent PDUs held the largest 2025 share.",
   "refs": [
    "digest:tam-global-crosscheck#c2",
    "ledger:tamBase",
    "profile:Product"
   ]
  },
  {
   "step": "propagation",
   "text": "Vendors sell intelligent and basic PDUs as separate products.",
   "refs": [
    "digest:tam-global-crosscheck#c12",
    "digest:tam-global-crosscheck#c13",
    "digest:tam-base#c14"
   ]
  },
  {
   "step": "model-impact",
   "text": "SAM €165M and YAM €1.65M both inherit the inflation.",
   "refs": [
    "ledger:tamBase",
    "ledger:serviceableFactor"
   ]
  }
 ],
 "falsifier": "A European source showing intelligent PDUs at 75% or more of rack-PDU revenue.",
 "category": "fact",
 "evidence": []
}

THE LEDGER FACTS IT TARGETS (current values, derivations, bands):
[
 {
  "id": "tamBase",
  "label": "Central Europe rack-PDU market, all segments/buyers",
  "kind": "estimated",
  "value": 300,
  "unit": "EUR_M",
  "confidence": "inferred",
  "maturity": "triangulated",
  "dimension": null,
  "dimensionValue": null,
  "sensitivityRange": {
   "low": 240,
   "high": 360
  },
  "funnelActive": true,
  "derivation": {
   "method": "Top-down scope-down from the global rack-PDU base",
   "expression": "Global rack-PDU $2.81B (Grand View, 2025) × Europe ≈ 30% [est.; NA = 38% per same source] ≈ $843M ≈ €775M @0.92 (Jul 2026) × CE-7 = 39.8% of Europe colo MW (Statista 2025) ≈ €310M → curated €300M",
   "crossCheck": "Refinement cycle 1: the prior €495M ceiling (BIS/R&M €2.45B) measures PDUs+PSUs combined — a broader category growing 21% CAGR vs intelligent-PDU 10–12% (IndexBox). Contaminated ceiling removed; band top lowered to €360M."
  },
  "provenance": {
   "rationale": "No public Europe- or CE-scoped rack-PDU figure exists; the scope-down chain anchors the value, and refinement cycle 1 killed the inflated PDUs+PSUs cross-check ceiling.",
   "promotionPath": "Commission the IndexBox EU Rack PDUs report (country tables) to pin the EU base directly."
  },
  "evidence": [
   {
    "title": "Data Center Rack PDU Market Size | Industry Report, 2033",
    "sourceType": "industry-report",
    "publisher": "Grand View Research",
    "date": "2025",
    "excerpt": "The global data center rack power distribution unit market size was estimated at USD 2.81 billion in 2025 and is projected to reach USD 5.87 billion by 2033... North America held 38.0% revenue share.",
    "attached": true
   },
   {
    "title": "Europe Data Center PDUs and PSUs Market 2025–2035",
    "sourceType": "industry-report",
    "publisher": "Research and Markets / BIS Research",
    "date": "2025",
    "excerpt": "The Europe data center PDUs and PSUs market is projected to reach $20.05 billion by 2035 from $2.45 billion in 2024 — a broader category (PDUs + PSUs) used as the cross-check ceiling.",
    "attached": true
   },
   {
    "title": "IndexBox — Rack PDUs Market in the European Union (country tables)",
    "sourceType": "pending",
    "publisher": "IndexBox",
    "date": null,
    "excerpt": "The directly-scoped EU rack-PDU report exists but its headline figure is paywalled — commissioning it would collapse the ±40% band.",
    "attached": false
   }
  ]
 }
]

Emit JSON: { resolution: "error"|"risk", settleTest, proposedCorrection: {nodeId, value, low, high, rationale} or null, researchQueries: [{query, kind}] ([] for risks) }
